    doc.add_heading("1 \u524d\u8a00", level=1)
    add_paragraph(doc, "\u968f\u7740\u4e92\u8054\u7f51\u5e94\u7528\u548c\u521b\u4f5c\u5e73\u53f0\u7684\u5feb\u901f\u53d1\u5c55\uff0c\u96c6\u5185\u5bb9\u53d1\u5e03\u3001\u4f5c\u54c1\u5c55\u793a\u3001\u4ea4\u4e92\u4ea4\u6d41\u3001\u540e\u53f0\u8fd0\u8425\u4e8e\u4e00\u4f53\u7684 Web \u7cfb\u7edf\u8d8a\u6765\u8d8a\u666e\u904d\u3002\u8bba\u575b\u7c7b\u9879\u76ee\u65e2\u8981\u4fdd\u8bc1\u524d\u53f0\u6d4f\u89c8\u4f53\u9a8c\uff0c\u53c8\u8981\u517c\u987e\u5185\u5bb9\u5ba1\u6838\u3001\u7528\u6237\u6743\u9650\u3001\u6570\u636e\u5b89\u5168\u548c\u7cfb\u7edf\u53ef\u7ef4\u62a4\u6027\uff0c\u56e0\u6b64\u8f6f\u4ef6\u6d4b\u8bd5\u5728\u9879\u76ee\u4ea4\u4ed8\u4e2d\u7684\u4f5c\u7528\u5c24\u4e3a\u91cd\u8981\u3002")
    add_paragraph(doc, "CreatorSpace \u662f\u4e00\u4e2a\u517c\u5177\u4e2a\u4eba\u535a\u5ba2\u3001\u8bba\u575b\u4ea4\u6d41\u548c\u521b\u610f\u4f5c\u54c1\u5c55\u793a\u5c5e\u6027\u7684\u7efc\u5408\u5e73\u53f0\uff0c\u5305\u542b\u6587\u7ae0\u3001\u9879\u76ee\u3001\u7075\u611f\u3001\u7559\u8a00\u3001\u8bc4\u8bba\u3001\u641c\u7d22\u3001\u521b\u4f5c\u8005\u4e2d\u5fc3\u3001\u540e\u53f0\u7ba1\u7406\u4ee5\u53ca AI \u8f85\u52a9\u8fd0\u8425\u7b49\u6a21\u5757\u3002\u9879\u76ee\u91c7\u7528\u524d\u540e\u7aef\u5206\u79bb\u67b6\u6784\uff0c\u6d89\u53ca Spring Boot\u3001Vue\u3001PostgreSQL\u3001Redis\u3001Docker \u7b49\u591a\u9879\u6280\u672f\uff0c\u6a21\u5757\u4e4b\u95f4\u8054\u7cfb\u7d27\u5bc6\uff0c\u4efb\u4f55\u5355\u70b9\u7f3a\u9677\u90fd\u53ef\u80fd\u5f71\u54cd\u6574\u4f53\u53ef\u7528\u6027\u3002")
    add_paragraph(doc, "\u672c\u62a5\u544a\u4ee5 CreatorSpace \u8bba\u575b\u9879\u76ee\u7684\u771f\u5b9e\u4ee3\u7801\u7ed3\u6784\u3001\u5df2\u6709\u63a5\u53e3\u3001\u524d\u7aef\u9875\u9762\u3001\u81ea\u52a8\u5316\u6d4b\u8bd5\u76ee\u5f55\u53ca\u90e8\u7f72\u914d\u7f6e\u4e3a\u4f9d\u636e\uff0c\u53c2\u7167\u8bfe\u7a0b\u7ed9\u5b9a\u6d4b\u8bd5\u62a5\u544a\u7684\u5f62\u5f0f\uff0c\u5bf9\u9879\u76ee\u7684\u8f6f\u4ef6\u6d4b\u8bd5\u5de5\u4f5c\u8fdb\u884c\u6574\u7406\u8bf4\u660e\u3002\u62a5\u544a\u91cd\u70b9\u4ece\u8f6f\u4ef6\u6d4b\u8bd5\u57fa\u672c\u7406\u8bba\u3001\u9879\u76ee\u7ed3\u6784\u5206\u6790\u3001\u6d4b\u8bd5\u8ba1\u5212\u3001\u6d4b\u8bd5\u8303\u56f4\u4e0e\u5b9e\u65bd\u5b89\u6392\u7b49\u65b9\u9762\u5c55\u5f00\u3002\u5176\u4e2d\u6d89\u53ca\u5177\u4f53\u201c\u6d4b\u8bd5\u7528\u4f8b\u201d\u7684\u4f4d\u7f6e\uff0c\u6309\u7167\u8981\u6c42\u6682\u4e0d\u586b\u5199\uff0c\u540e\u7eed\u53ef\u5728\u5b9e\u9645\u6267\u884c\u6d4b\u8bd5\u65f6\u7ee7\u7eed\u8865\u5145\u3002")

    doc.add_heading("2 \u8f6f\u4ef6\u6d4b\u8bd5\u6982\u8ff0", level=1)
    doc.add_heading("2.1 \u8f6f\u4ef6\u6d4b\u8bd5\u7684\u6982\u5ff5", level=2)
    add_paragraph(doc, "\u8f6f\u4ef6\u6d4b\u8bd5\u662f\u5728\u89c4\u5b9a\u6761\u4ef6\u4e0b\u5bf9\u7cfb\u7edf\u8fdb\u884c\u68c0\u67e5\u3001\u9a8c\u8bc1\u548c\u8bc4\u4ef7\u7684\u8fc7\u7a0b\uff0c\u5176\u6838\u5fc3\u76ee\u7684\u662f\u5c3d\u53ef\u80fd\u65e9\u5730\u53d1\u73b0\u8f6f\u4ef6\u4e2d\u7684\u9519\u8bef\u3001\u7f3a\u9677\u4e0e\u98ce\u9669\uff0c\u5e76\u636e\u6b64\u6539\u8fdb\u7cfb\u7edf\u8d28\u91cf\u3002\u5bf9 Web \u9879\u76ee\u800c\u8a00\uff0c\u6d4b\u8bd5\u5bf9\u8c61\u4e0d\u4ec5\u5305\u62ec\u524d\u7aef\u9875\u9762\u548c\u540e\u7aef\u7a0b\u5e8f\uff0c\u4e5f\u5305\u62ec\u63a5\u53e3\u8bbe\u8ba1\u3001\u6743\u9650\u63a7\u5236\u3001\u6570\u636e\u5e93\u8fc1\u79fb\u3001\u7f13\u5b58\u7b56\u7565\u3001\u90e8\u7f72\u94fe\u8def\u53ca\u7528\u6237\u4ea4\u4e92\u8fc7\u7a0b\u3002")
    doc.add_heading("2.2 \u6d4b\u8bd5\u7684\u76ee\u7684", level=2)
    add_paragraph(doc, "\u5bf9 CreatorSpace \u9879\u76ee\u8fdb\u884c\u6d4b\u8bd5\uff0c\u4e3b\u8981\u662f\u4e3a\u4e86\u9a8c\u8bc1\u7cfb\u7edf\u662f\u5426\u6ee1\u8db3\u8bba\u575b\u9879\u76ee\u5728\u5185\u5bb9\u5c55\u793a\u3001\u7528\u6237\u8ba4\u8bc1\u3001\u6295\u7a3f\u5ba1\u6838\u3001\u4e92\u52a8\u4ea4\u6d41\u548c\u540e\u53f0\u8fd0\u8425\u65b9\u9762\u7684\u4e1a\u52a1\u8981\u6c42\uff1b\u68c0\u67e5\u4e0d\u540c\u6a21\u5757\u5728\u771f\u5b9e\u8bbf\u95ee\u6d41\u7a0b\u4e2d\u662f\u5426\u534f\u540c\u6b63\u5e38\uff1b\u53d1\u73b0\u6f5c\u5728\u7684\u529f\u80fd\u9519\u8bef\u3001\u6743\u9650\u6f0f\u6d1e\u3001\u6570\u636e\u4e00\u81f4\u6027\u95ee\u9898\u548c\u53ef\u7528\u6027\u7f3a\u9677\uff1b\u5e76\u4e3a\u540e\u7eed\u4f18\u5316\u548c\u6b63\u5f0f\u4ea4\u4ed8\u63d0\u4f9b\u4f9d\u636e\u3002")
    doc.add_heading("2.3 \u6d4b\u8bd5\u7684\u539f\u5219", level=2)
    principles = [
        "\uff081\uff09\u6240\u6709\u6d4b\u8bd5\u6d3b\u52a8\u5747\u5e94\u8ffd\u6eaf\u5230\u9879\u76ee\u7684\u9700\u6c42\u3001\u9875\u9762\u529f\u80fd\u548c\u63a5\u53e3\u8bbe\u8ba1\u3002",
        "\uff082\uff09\u6d4b\u8bd5\u5e94\u5c3d\u65e9\u5f00\u5c55\uff0c\u5e76\u4f34\u968f\u5f00\u53d1\u3001\u8054\u8c03\u548c\u90e8\u7f72\u8fc7\u7a0b\u6301\u7eed\u8fdb\u884c\u3002",
        "\uff083\uff09\u6d4b\u8bd5\u4e0d\u53ef\u80fd\u7a77\u5c3d\u6240\u6709\u573a\u666f\uff0c\u5e94\u4f18\u5148\u8986\u76d6\u9ad8\u9891\u3001\u9ad8\u98ce\u9669\u548c\u6838\u5fc3\u4e1a\u52a1\u8def\u5f84\u3002",
        "\uff084\uff09\u6d4b\u8bd5\u53ea\u80fd\u8bf4\u660e\u7cfb\u7edf\u5f53\u524d\u5df2\u77e5\u573a\u666f\u4e0b\u7684\u8d28\u91cf\u72b6\u6001\uff0c\u4e0d\u80fd\u8bc1\u660e\u7cfb\u7edf\u7edd\u5bf9\u6ca1\u6709\u7f3a\u9677\u3002",
        "\uff085\uff09\u529f\u80fd\u3001\u6743\u9650\u3001\u6570\u636e\u3001\u6027\u80fd\u548c\u6613\u7528\u6027\u95ee\u9898\u5f80\u5f80\u5177\u6709\u96c6\u4e2d\u51fa\u73b0\u7684\u7279\u70b9\uff0c\u5e94\u52a0\u5f3a\u91cd\u70b9\u6a21\u5757\u56de\u5f52\u3002",
        "\uff086\uff09\u5f00\u53d1\u8005\u81ea\u6d4b\u4e0e\u72ec\u7acb\u6d4b\u8bd5\u7ed3\u5408\uff0c\u80fd\u591f\u66f4\u6709\u6548\u5730\u964d\u4f4e\u9057\u6f0f\u3002",
        "\uff087\uff09\u6d4b\u8bd5\u8fc7\u7a0b\u5e94\u89c4\u8303\u8bb0\u5f55\uff0c\u4fbf\u4e8e\u7f3a\u9677\u8ddf\u8e2a\u3001\u590d\u73b0\u548c\u540e\u7eed\u5206\u6790\u3002",
    ]
    for line in principles:
        add_paragraph(doc, line)
    doc.add_heading("2.4 Web\u6d4b\u8bd5\u6982\u8ff0", level=2)
    add_paragraph(doc, "Web \u7cfb\u7edf\u6d4b\u8bd5\u9664\u4e86\u4f20\u7edf\u7684\u8f6f\u4ef6\u529f\u80fd\u9a8c\u8bc1\u5916\uff0c\u8fd8\u9700\u8981\u5173\u6ce8\u6d4f\u89c8\u5668\u7aef\u5c55\u793a\u3001\u524d\u540e\u7aef\u63a5\u53e3\u4ea4\u4e92\u3001\u4f1a\u8bdd\u4e0e\u8eab\u4efd\u8ba4\u8bc1\u3001\u6570\u636e\u5e93\u6301\u4e45\u5316\u3001\u7f13\u5b58\u4e00\u81f4\u6027\u3001\u9759\u6001\u8d44\u6e90\u8bbf\u95ee\u3001\u4e0a\u4f20\u6587\u4ef6\u5904\u7406\u3001\u9875\u9762\u8def\u7531\u8df3\u8f6c\u4ee5\u53ca\u90e8\u7f72\u540e\u7684\u5165\u53e3\u53ef\u7528\u6027\u7b49\u95ee\u9898\u3002")
    add_paragraph(doc, "CreatorSpace \u5c5e\u4e8e\u5178\u578b\u7684\u524d\u540e\u7aef\u5206\u79bb Web \u5e94\u7528\u3002\u524d\u7aef\u901a\u8fc7 Vue Router \u7ec4\u7ec7\u9875\u9762\uff0c\u901a\u8fc7 HTTP \u63a5\u53e3\u4e0e Spring Boot \u540e\u7aef\u901a\u4fe1\uff1b\u540e\u7aef\u8d1f\u8d23\u4e1a\u52a1\u5904\u7406\u3001\u6743\u9650\u6821\u9a8c\u3001\u6570\u636e\u5e93\u8bbf\u95ee\u548c\u7f13\u5b58\u8bfb\u5199\uff1b\u7cfb\u7edf\u8fd8\u4f9d\u8d56 PostgreSQL\u3001Redis\u3001Flyway \u548c Docker Compose\u3002\u56e0\u6b64\u5728\u6d4b\u8bd5\u4e2d\u65e2\u8981\u5173\u6ce8\u5355\u4e00\u9875\u9762\u6216\u63a5\u53e3\u7684\u6b63\u786e\u6027\uff0c\u4e5f\u8981\u5173\u6ce8\u8de8\u6a21\u5757\u7684\u5b8c\u6574\u4e1a\u52a1\u94fe\u8def\u3002")

    doc.add_heading("3 \u7f51\u7ad9\u5185\u5bb9\u7ed3\u6784\u7b80\u4ecb", level=1)
    add_paragraph(doc, "CreatorSpace \u662f\u4e00\u4e2a\u57fa\u4e8e\u521b\u4f5c\u8005\u5c55\u793a\u4e0e\u8bba\u575b\u4e92\u52a8\u573a\u666f\u6784\u5efa\u7684\u7efc\u5408\u5e73\u53f0\u3002\u6839\u636e\u9879\u76ee\u6e90\u7801\u4e2d\u7684\u524d\u7aef\u8def\u7531\u3001\u540e\u7aef\u63a7\u5236\u5668\u3001README \u4e0e\u90e8\u7f72\u914d\u7f6e\uff0c\u5f53\u524d\u7cfb\u7edf\u4e3b\u8981\u7531\u516c\u5171\u524d\u53f0\u3001\u7528\u6237\u8ba4\u8bc1\u3001\u521b\u4f5c\u8005\u4e2d\u5fc3\u3001\u540e\u53f0\u7ba1\u7406\u3001\u4ea4\u4e92\u80fd\u529b\u548c\u57fa\u7840\u652f\u6491\u7b49\u90e8\u5206\u7ec4\u6210\u3002\u524d\u53f0\u9762\u5411\u8bbf\u5ba2\u63d0\u4f9b\u6587\u7ae0\u3001\u9879\u76ee\u3001\u7075\u611f\u3001\u641c\u7d22\u3001\u7559\u8a00\u7b49\u516c\u5f00\u6d4f\u89c8\u80fd\u529b\uff1b\u767b\u5f55\u7528\u6237\u53ef\u4ee5\u8fdb\u5165\u521b\u4f5c\u8005\u4e2d\u5fc3\u7ef4\u62a4\u4e2a\u4eba\u5185\u5bb9\uff1b\u7ba1\u7406\u5458\u5219\u901a\u8fc7\u540e\u53f0\u5bf9\u5e73\u53f0\u5185\u5bb9\u548c\u8fd0\u8425\u6570\u636e\u8fdb\u884c\u7ba1\u7406\u3002")
    add_paragraph(doc, "\u4ece\u67b6\u6784\u5b9e\u73b0\u770b\uff0c\u524d\u7aef\u91c7\u7528 Vue 3\u3001TypeScript\u3001Vite\u3001Vue Router\u3001Pinia \u7b49\u6280\u672f\u5b9e\u73b0\u9875\u9762\u4ea4\u4e92\uff1b\u540e\u7aef\u91c7\u7528 Spring Boot\u3001Spring Security\u3001MyBatis-Plus\u3001Flyway \u548c Redis \u6784\u5efa\u4e1a\u52a1\u670d\u52a1\uff1b\u6570\u636e\u5c42\u4f7f\u7528 PostgreSQL\uff0c\u5e76\u901a\u8fc7 Docker Compose \u7ec4\u7ec7\u524d\u7aef\u3001\u540e\u7aef\u3001\u6570\u636e\u5e93\u4e0e\u7f13\u5b58\u670d\u52a1\u3002\u6574\u4f53\u7ed3\u6784\u5177\u6709\u5178\u578b\u7684\u73b0\u4ee3 Web \u8bba\u575b\u7cfb\u7edf\u7279\u5f81\u3002")
    add_paragraph(doc, "\u88683.1 CreatorSpace \u529f\u80fd\u6a21\u5757")
    add_module_table(doc)

    doc.add_heading("4 \u5236\u5b9a\u6d4b\u8bd5\u8ba1\u5212", level=1)
    doc.add_heading("4.1 \u6d4b\u8bd5\u5185\u5bb9", level=2)
    add_paragraph(doc, "\u7ed3\u5408 CreatorSpace \u9879\u76ee\u7684\u5b9e\u9645\u60c5\u51b5\uff0c\u672c\u6b21\u6d4b\u8bd5\u8ba1\u5212\u4e3b\u8981\u56f4\u7ed5\u529f\u80fd\u6d4b\u8bd5\u3001\u6613\u7528\u6027\u6d4b\u8bd5\u548c\u57fa\u7840\u6027\u80fd/\u8d1f\u8f7d\u6d4b\u8bd5\u4e09\u4e2a\u65b9\u9762\u5c55\u5f00\u3002\u7531\u4e8e\u7cfb\u7edf\u529f\u80fd\u6a21\u5757\u8f83\u591a\uff0c\u6d4b\u8bd5\u65f6\u5e94\u4f18\u5148\u8986\u76d6\u8ba4\u8bc1\u6743\u9650\u3001\u6587\u7ae0\u9879\u76ee\u53d1\u5e03\u3001\u8bc4\u8bba\u7559\u8a00\u4e92\u52a8\u3001\u641c\u7d22\u68c0\u7d22\u3001\u540e\u53f0\u5ba1\u6838\u3001\u6587\u4ef6\u4e0a\u4f20\u548c\u5065\u5eb7\u68c0\u67e5\u7b49\u6838\u5fc3\u94fe\u8def\u3002")
    add_paragraph(doc, "4.1.1 \u529f\u80fd\u6d4b\u8bd5")
    add_paragraph(doc, "\u529f\u80fd\u6d4b\u8bd5\u4e3b\u8981\u9a8c\u8bc1\u7cfb\u7edf\u662f\u5426\u6309\u7167\u524d\u7aef\u9875\u9762\u548c\u540e\u7aef\u63a5\u53e3\u8bbe\u8ba1\u6b63\u786e\u5b8c\u6210\u4e1a\u52a1\u5904\u7406\u3002\u5177\u4f53\u5305\u62ec\uff1a\u7528\u6237\u6ce8\u518c\u767b\u5f55\u4e0e\u4ee4\u724c\u5237\u65b0\uff0c\u6587\u7ae0\u548c\u9879\u76ee\u7684\u589e\u5220\u6539\u67e5\u53ca\u63d0\u4ea4\u6d41\u7a0b\uff0c\u5206\u7c7b\u6807\u7b7e\u83b7\u53d6\uff0c\u641c\u7d22\u7ed3\u679c\u5c55\u793a\uff0c\u8bc4\u8bba\u7559\u8a00\u53d1\u8868\u4e0e\u5ba1\u6838\uff0c\u70b9\u8d5e\u6536\u85cf\uff0c\u597d\u53cb\u7533\u8bf7\uff0c\u540e\u53f0\u7ba1\u7406\u3001\u7edf\u8ba1\u4e0e AI \u52a9\u624b\u63a5\u53e3\u7b49\u3002\u5bf9\u524d\u53f0\u9875\u9762\u800c\u8a00\uff0c\u8fd8\u9700\u8981\u68c0\u67e5\u8def\u7531\u8df3\u8f6c\u3001\u6570\u636e\u52a0\u8f7d\u3001\u5f02\u5e38\u63d0\u793a\u548c\u6743\u9650\u62e6\u622a\u662f\u5426\u7b26\u5408\u9884\u671f\u3002")
    add_paragraph(doc, "4.1.2 \u6613\u7528\u6027\u6d4b\u8bd5")
    add_paragraph(doc, "\u6613\u7528\u6027\u6d4b\u8bd5\u5173\u6ce8\u9875\u9762\u89c6\u89c9\u4e00\u81f4\u6027\u3001\u5bfc\u822a\u6e05\u6670\u5ea6\u3001\u64cd\u4f5c\u4fbf\u6377\u6027\u548c\u63d0\u793a\u53cb\u597d\u6027\u3002CreatorSpace \u5177\u6709\u9996\u9875\u3001\u516c\u5f00\u9875\u3001\u521b\u4f5c\u8005\u4e2d\u5fc3\u548c\u540e\u53f0\u9875\u7b49\u591a\u79cd\u754c\u9762\u5f62\u6001\uff0c\u56e0\u6b64\u5e94\u91cd\u70b9\u68c0\u67e5\u4e0d\u540c\u5e03\u5c40\u4e4b\u95f4\u7684\u5207\u6362\u662f\u5426\u81ea\u7136\uff0c\u8868\u5355\u8f93\u5165\u662f\u5426\u660e\u786e\uff0c\u5ba1\u6838\u4e0e\u7ba1\u7406\u64cd\u4f5c\u662f\u5426\u5bb9\u6613\u7406\u89e3\uff0c\u4ee5\u53ca\u52a8\u6548\u3001\u56fe\u7247\u548c\u5bcc\u6587\u672c\u5c55\u793a\u662f\u5426\u5f71\u54cd\u6b63\u5e38\u4f7f\u7528\u3002")
    add_paragraph(doc, "4.1.3 \u8d1f\u8f7d\u538b\u529b\u6d4b\u8bd5")
    add_paragraph(doc, "\u8d1f\u8f7d\u538b\u529b\u6d4b\u8bd5\u7528\u4e8e\u8bc4\u4f30\u7cfb\u7edf\u5728\u4e00\u5b9a\u5e76\u53d1\u8bbf\u95ee\u6761\u4ef6\u4e0b\u7684\u7a33\u5b9a\u6027\u548c\u54cd\u5e94\u80fd\u529b\u3002\u5bf9\u4e8e\u8bba\u575b\u9879\u76ee\uff0c\u91cd\u70b9\u5173\u6ce8\u9996\u9875\u8bbf\u95ee\u3001\u6587\u7ae0\u5217\u8868\u4e0e\u8be6\u60c5\u8bbf\u95ee\u3001\u641c\u7d22\u8bf7\u6c42\u3001\u767b\u5f55\u64cd\u4f5c\u3001\u8bc4\u8bba\u63d0\u4ea4\u548c\u540e\u53f0\u5217\u8868\u67e5\u8be2\u7b49\u5178\u578b\u63a5\u53e3\u5728\u5e76\u53d1\u4e0b\u7684\u8868\u73b0\u3002\u540c\u65f6\u9700\u8981\u7ed3\u5408\u6570\u636e\u5e93\u3001Redis \u548c Docker \u90e8\u7f72\u73af\u5883\uff0c\u89c2\u5bdf\u7cfb\u7edf\u662f\u5426\u51fa\u73b0\u660e\u663e\u7684\u6027\u80fd\u74f6\u9888\u3002")
    doc.add_heading("4.2 \u6d4b\u8bd5\u73af\u5883", level=2)
    add_paragraph(doc, "\uff081\uff09\u786c\u4ef6\u73af\u5883\uff1a\u4f7f\u7528\u666e\u901a\u5f00\u53d1\u673a\u8fdb\u884c\u672c\u5730\u8054\u8c03\u4e0e\u6d4b\u8bd5\uff0c\u5177\u5907\u8fd0\u884c JDK\u3001Node.js\u3001Docker Desktop\u3001PostgreSQL \u548c Redis \u7684\u80fd\u529b\u3002")
    add_paragraph(doc, "\uff082\uff09\u8f6f\u4ef6\u73af\u5883\uff1a\u540e\u7aef\u91c7\u7528 Java 21\u3001Spring Boot 3.5.7\u3001Maven 3.9+\uff1b\u524d\u7aef\u91c7\u7528 Node.js 24\u3001Vue 3\u3001TypeScript\u3001Vite 8\uff1b\u6570\u636e\u5e93\u4e3a PostgreSQL 17\uff08\u542b pgvector \u955c\u50cf\uff09\uff0c\u7f13\u5b58\u4e3a Redis 7\u3002")
    add_paragraph(doc, "\uff083\uff09\u90e8\u7f72\u73af\u5883\uff1a\u9879\u76ee\u652f\u6301\u672c\u5730\u5f00\u53d1\u6a21\u5f0f\u4e0e Docker Compose \u6a21\u5f0f\u3002Compose \u6587\u4ef6\u5b9a\u4e49\u4e86 frontend\u3001backend\u3001postgres\u3001redis \u56db\u4e2a\u670d\u52a1\uff0c\u524d\u7aef\u9ed8\u8ba4\u7ecf Nginx \u5bf9\u5916\u63d0\u4f9b\u8bbf\u95ee\uff0c\u540e\u7aef\u66b4\u9732 /api/health \u7528\u4e8e\u5065\u5eb7\u68c0\u67e5\u3002")
    add_paragraph(doc, "\uff084\uff09\u6d4b\u8bd5\u652f\u6491\u73af\u5883\uff1a\u540e\u7aef\u6d4b\u8bd5\u76ee\u5f55\u5df2\u5305\u542b JUnit 5\u3001Spring Boot Test\u3001Spring Security Test\u3001Testcontainers\u3001Flyway \u8fc1\u79fb\u6d4b\u8bd5\u4e0e\u82e5\u5e72\u96c6\u6210\u6d4b\u8bd5\u7c7b\uff0c\u53ef\u4f5c\u4e3a\u81ea\u52a8\u5316\u56de\u5f52\u7684\u57fa\u7840\u3002")
    doc.add_heading("4.3 \u6d4b\u8bd5\u65b9\u6cd5", level=2)
    add_paragraph(doc, "\u672c\u9879\u76ee\u6d4b\u8bd5\u65b9\u6cd5\u4ee5\u9ed1\u76d2\u6d4b\u8bd5\u4e3a\u4e3b\uff0c\u7ed3\u5408\u63a5\u53e3\u7ea7\u6d4b\u8bd5\u3001\u9875\u9762\u4ea4\u4e92\u6d4b\u8bd5\u3001\u6743\u9650\u9a8c\u8bc1\u6d4b\u8bd5\u548c\u81ea\u52a8\u5316\u56de\u5f52\u6d4b\u8bd5\u3002\u5bf9\u5df2\u6709\u4ee3\u7801\u57fa\u7840\uff0c\u53ef\u91c7\u7528\u4ee5\u4e0b\u7ec4\u5408\u65b9\u5f0f\uff1a")
    add_paragraph(doc, "\uff081\uff09\u624b\u5de5\u6d4b\u8bd5\uff1a\u56f4\u7ed5\u524d\u7aef\u9875\u9762\u6d41\u7a0b\u3001\u8868\u5355\u8f93\u5165\u3001\u5ba1\u6838\u64cd\u4f5c\u3001\u5f02\u5e38\u63d0\u793a\u548c\u8de8\u9875\u9762\u8df3\u8f6c\u8fdb\u884c\u4eba\u5de5\u9a8c\u8bc1\u3002")
    add_paragraph(doc, "\uff082\uff09\u63a5\u53e3\u6d4b\u8bd5\uff1a\u57fa\u4e8e\u540e\u7aef\u63a7\u5236\u5668\u66b4\u9732\u7684 REST API\uff0c\u5bf9\u8bf7\u6c42\u53c2\u6570\u3001\u8fd4\u56de\u7ed3\u679c\u3001\u6743\u9650\u63a7\u5236\u548c\u5f02\u5e38\u5904\u7406\u8fdb\u884c\u9a8c\u8bc1\u3002")
    add_paragraph(doc, "\uff083\uff09\u81ea\u52a8\u5316\u6d4b\u8bd5\uff1a\u9879\u76ee\u5df2\u6709 ContentApiIntegrationTests\u3001SearchEnhancementIntegrationTests\u3001SearchSecurityIntegrationTests\u3001DashboardControllerTests\u3001AiAssistantControllerTests \u7b49\u6d4b\u8bd5\u7c7b\uff0c\u53ef\u7528\u4e8e\u56de\u5f52\u9a8c\u8bc1\u3002")
    add_paragraph(doc, "\uff084\uff09\u90e8\u7f72\u9a8c\u8bc1\uff1a\u901a\u8fc7 mvn -f backend/pom.xml test\u3001npm run build --prefix frontend\u3001docker compose config --quiet \u7b49\u547d\u4ee4\u68c0\u67e5\u6784\u5efa\u4e0e\u90e8\u7f72\u94fe\u8def\u3002")
    doc.add_heading("4.4 \u6d4b\u8bd5\u901a\u8fc7\u6807\u51c6", level=2)
    add_paragraph(doc, "\uff081\uff09\u88ab\u6d4b\u529f\u80fd\u5728\u6ee1\u8db3\u524d\u7f6e\u6761\u4ef6\u65f6\uff0c\u5b9e\u9645\u7ed3\u679c\u4e0e\u9884\u671f\u7ed3\u679c\u4e00\u81f4\uff0c\u53ef\u5224\u5b9a\u4e3a\u901a\u8fc7\u3002")
    add_paragraph(doc, "\uff082\uff09\u5bf9\u4e8e\u53d7\u6743\u9650\u4fdd\u62a4\u7684\u63a5\u53e3\u548c\u9875\u9762\uff0c\u672a\u6388\u6743\u8bbf\u95ee\u5e94\u88ab\u6b63\u786e\u62e6\u622a\uff0c\u6388\u6743\u8bbf\u95ee\u5e94\u6b63\u5e38\u901a\u8fc7\u3002")
    add_paragraph(doc, "\uff083\uff09\u6d89\u53ca\u6570\u636e\u5e93\u5199\u5165\u3001\u5ba1\u6838\u72b6\u6001\u6d41\u8f6c\u3001\u70b9\u8d5e\u6536\u85cf\u3001\u6587\u4ef6\u4e0a\u4f20\u7b49\u64cd\u4f5c\u65f6\uff0c\u6570\u636e\u5e94\u4fdd\u6301\u6b63\u786e\u3001\u4e00\u81f4\u4e14\u53ef\u8ffd\u8e2a\u3002")
    add_paragraph(doc, "\uff084\uff09\u82e5\u7cfb\u7edf\u51fa\u73b0\u63a5\u53e3\u62a5\u9519\u3001\u9875\u9762\u767d\u5c4f\u3001\u6d41\u7a0b\u4e2d\u65ad\u3001\u6570\u636e\u6c61\u67d3\u6216\u670d\u52a1\u5d29\u6e83\uff0c\u5219\u5224\u5b9a\u8be5\u9879\u6d4b\u8bd5\u4e0d\u901a\u8fc7\u3002")

    doc.add_heading("5 \u6d4b\u8bd5\u7528\u4f8b\u7684\u8bbe\u8ba1\u4e0e\u5b9e\u65bd", level=1)
    add_paragraph(doc, "\u6d4b\u8bd5\u7528\u4f8b\u7528\u4e8e\u628a\u6d4b\u8bd5\u76ee\u6807\u3001\u8f93\u5165\u52a8\u4f5c\u3001\u9884\u671f\u7ed3\u679c\u4e0e\u5b9e\u9645\u7ed3\u679c\u8fdb\u884c\u7ed3\u6784\u5316\u8bb0\u5f55\uff0c\u662f\u6267\u884c\u6d4b\u8bd5\u548c\u5206\u6790\u7f3a\u9677\u7684\u91cd\u8981\u4f9d\u636e\u3002\u7ed3\u5408 CreatorSpace \u9879\u76ee\u7684\u529f\u80fd\u7ed3\u6784\uff0c\u672c\u7ae0\u539f\u672c\u5e94\u6309\u7167\u6838\u5fc3\u4e1a\u52a1\u6a21\u5757\u5206\u522b\u8bbe\u8ba1\u6d4b\u8bd5\u7528\u4f8b\u3002\u6309\u7167\u5f53\u524d\u8981\u6c42\uff0c\u51e1\u6d89\u53ca\u5177\u4f53\u6d4b\u8bd5\u7528\u4f8b\u7684\u5730\u65b9\u6682\u4e0d\u586b\u5199\u8be6\u7ec6\u5185\u5bb9\uff0c\u4ec5\u4fdd\u7559\u7ae0\u8282\u7ed3\u6784\u4e0e\u5f85\u8865\u5145\u4f4d\u7f6e\uff0c\u4fbf\u4e8e\u540e\u7eed\u7ee7\u7eed\u5b8c\u5584\u3002")
    doc.add_heading("5.1 \u529f\u80fd\u6d4b\u8bd5", level=2)
    add_paragraph(doc, "CreatorSpace \u5305\u542b\u7528\u6237\u8ba4\u8bc1\u3001\u6587\u7ae0\u3001\u9879\u76ee\u3001\u641c\u7d22\u3001\u8bc4\u8bba\u3001\u7559\u8a00\u3001\u4ea4\u4e92\u3001\u521b\u4f5c\u8005\u4e2d\u5fc3\u3001\u540e\u53f0\u7ba1\u7406\u548c AI \u80fd\u529b\u7b49\u6a21\u5757\u3002\u4e0b\u9762\u6309\u7167\u4e3b\u8981\u4e1a\u52a1\u6a21\u5757\u5212\u5206\u6d4b\u8bd5\u4f4d\u7f6e\u3002")
    sections = [
        ("5.1.1 \u7528\u6237\u8ba4\u8bc1\u4e0e\u6743\u9650\u6a21\u5757\u6d4b\u8bd5", "\u672c\u6a21\u5757\u4e3b\u8981\u5305\u62ec\u666e\u901a\u7528\u6237\u6ce8\u518c\u3001\u767b\u5f55\u3001\u9000\u51fa\u3001\u5237\u65b0\u4ee4\u724c\uff0c\u4ee5\u53ca\u7ba1\u7406\u5458\u767b\u5f55\u3001\u8def\u7531\u6743\u9650\u63a7\u5236\u548c\u63a5\u53e3\u6743\u9650\u6821\u9a8c\u3002\u6d4b\u8bd5\u7528\u4f8b\u5f85\u8865\u5145\u3002", "\u88685.1 \u7528\u6237\u8ba4\u8bc1\u4e0e\u6743\u9650\u6a21\u5757\u6d4b\u8bd5\u7528\u4f8b\uff08\u5f85\u8865\u5145\uff09"),
        ("5.1.2 \u6587\u7ae0\u5185\u5bb9\u6a21\u5757\u6d4b\u8bd5", "\u672c\u6a21\u5757\u4e3b\u8981\u5305\u62ec\u6587\u7ae0\u5217\u8868\u3001\u6587\u7ae0\u8be6\u60c5\u3001\u4e0a\u4e00\u7bc7\u4e0b\u4e00\u7bc7\u3001\u521b\u4f5c\u8005\u6587\u7ae0\u521b\u5efa/\u7f16\u8f91/\u63d0\u4ea4\u3001\u7ba1\u7406\u5458\u6587\u7ae0\u5ba1\u6838/\u53d1\u5e03/\u7f6e\u9876/\u63a8\u8350/\u7248\u672c\u6062\u590d\u7b49\u6d41\u7a0b\u3002\u6d4b\u8bd5\u7528\u4f8b\u5f85\u8865\u5145\u3002", "\u88685.2 \u6587\u7ae0\u5185\u5bb9\u6a21\u5757\u6d4b\u8bd5\u7528\u4f8b\uff08\u5f85\u8865\u5145\uff09"),
        ("5.1.3 \u9879\u76ee\u4f5c\u54c1\u6a21\u5757\u6d4b\u8bd5", "\u672c\u6a21\u5757\u4e3b\u8981\u5305\u62ec\u9879\u76ee\u5217\u8868\u3001\u63a8\u8350\u7b5b\u9009\u3001\u9879\u76ee\u8be6\u60c5\u3001\u521b\u4f5c\u8005\u9879\u76ee\u6295\u7a3f\u3001\u7ba1\u7406\u5458\u9879\u76ee\u5ba1\u6838\u3001\u63a8\u8350\u548c\u72b6\u6001\u53d8\u66f4\u7b49\u6d41\u7a0b\u3002\u6d4b\u8bd5\u7528\u4f8b\u5f85\u8865\u5145\u3002", "\u88685.3 \u9879\u76ee\u4f5c\u54c1\u6a21\u5757\u6d4b\u8bd5\u7528\u4f8b\uff08\u5f85\u8865\u5145\uff09"),
        ("5.1.4 \u641c\u7d22\u4e0e\u5206\u7c7b\u6807\u7b7e\u6a21\u5757\u6d4b\u8bd5", "\u672c\u6a21\u5757\u4e3b\u8981\u5305\u62ec\u5168\u7ad9\u641c\u7d22\u3001\u5206\u7c7b\u83b7\u53d6\u3001\u6807\u7b7e\u83b7\u53d6\u3001\u63a8\u8350\u6807\u7b7e\u4e0e\u63a8\u8350\u7b5b\u9009\u7b49\u529f\u80fd\u3002\u6d4b\u8bd5\u7528\u4f8b\u5f85\u8865\u5145\u3002", "\u88685.4 \u641c\u7d22\u4e0e\u5206\u7c7b\u6807\u7b7e\u6a21\u5757\u6d4b\u8bd5\u7528\u4f8b\uff08\u5f85\u8865\u5145\uff09"),
        ("5.1.5 \u8bc4\u8bba\u7559\u8a00\u4e0e\u4ea4\u4e92\u6a21\u5757\u6d4b\u8bd5", "\u672c\u6a21\u5757\u4e3b\u8981\u5305\u62ec\u8bc4\u8bba\u53d1\u5e03\u3001\u8bc4\u8bba\u4fee\u6539\u5220\u9664\u3001\u6211\u7684\u8bc4\u8bba\u3001\u7559\u8a00\u677f\u53d1\u5e03\u3001\u540e\u53f0\u5ba1\u6838\u3001\u70b9\u8d5e\u3001\u6536\u85cf\u3001\u8bc4\u8bba\u53cd\u5e94\u548c\u597d\u53cb\u5173\u7cfb\u7b49\u529f\u80fd\u3002\u6d4b\u8bd5\u7528\u4f8b\u5f85\u8865\u5145\u3002", "\u88685.5 \u8bc4\u8bba\u7559\u8a00\u4e0e\u4ea4\u4e92\u6a21\u5757\u6d4b\u8bd5\u7528\u4f8b\uff08\u5f85\u8865\u5145\uff09"),
        ("5.1.6 \u521b\u4f5c\u8005\u4e2d\u5fc3\u4e0e\u540e\u53f0\u7ba1\u7406\u6a21\u5757\u6d4b\u8bd5", "\u672c\u6a21\u5757\u4e3b\u8981\u5305\u62ec\u521b\u4f5c\u8005\u4e2d\u5fc3\u9875\u9762\u3001\u6587\u4ef6\u4e0a\u4f20\u3001\u53ef\u89c1\u6027\u7ba1\u7406\u3001\u540e\u53f0\u4eea\u8868\u76d8\u3001\u5206\u7c7b\u6807\u7b7e\u7ba1\u7406\u3001\u654f\u611f\u8bcd\u7ba1\u7406\u3001\u64cd\u4f5c\u65e5\u5fd7\u3001\u4e3b\u9898\u914d\u7f6e\u3001\u7ad9\u70b9\u8bbe\u7f6e\u3001AI \u52a9\u624b\u4e0e\u7edf\u8ba1\u63a5\u53e3\u7b49\u3002\u6d4b\u8bd5\u7528\u4f8b\u5f85\u8865\u5145\u3002", "\u88685.6 \u521b\u4f5c\u8005\u4e2d\u5fc3\u4e0e\u540e\u53f0\u7ba1\u7406\u6a21\u5757\u6d4b\u8bd5\u7528\u4f8b\uff08\u5f85\u8865\u5145\uff09"),
    ]
    for heading, paragraph, table_title in sections:
        doc.add_heading(heading, level=3)
